#include <bits/stdc++.h>
using namespace std;
int n,m,c[10004],sum1,sum2,ans;
vector<int> g[10004];
bool dfs(int x){
    int len=g[x].size();
    for(int i=0;i<len;i++){
        if(!c[g[x][i]]){
            c[g[x][i]]=3-c[x];
            if(c[g[x][i]]==1)sum1++;
            else sum2++;
            if(!dfs(g[x][i]))return false;
        }else if(c[g[x][i]]==c[x])
            return false;
    }
    return true;
}
bool check(){
    for(int i=1;i<=n;i++)
        if(!c[i]){
            sum1=sum2=0;
            c[i]=1,sum1++;
            if(!dfs(i))
                return false;
            ans+=min(sum1,sum2);
        }
    return true;
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=m;i++){
        int u,v;
        cin>>u>>v;
        g[u].push_back(v);
        g[v].push_back(u);
    }
    if(!check())cout<<"Impossible";
    else cout<<ans;
    return 0;
}
